# -*- coding: utf-8 -*-
import sys
import os
import json
import numpy as np
import pandas as pd
from datetime import datetime, timedelta
import duckdb

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))

from data_engine.collector import Collector
from data_engine.factors import FactorEngine
from backtest_engine.engine import BacktestEngine, BacktestConfig
from backtest_engine.metrics import MetricsCalculator


class MainlineBacktestStrategy:
    def __init__(self, collector, concept_code, constituents):
        self.collector = collector
        self.concept_code = concept_code
        self.constituents = constituents
        self.factor_engine = FactorEngine()
        self.entry_score_threshold = 65
        self.exit_score_threshold = 50
        self.max_positions = 5
        self.position_pct = 0.15
        self.stop_loss_pct = -0.08
        self.take_profit_pct = 0.15
        self.holding_days = 0

    def generate_signals(self, daily_data, current_date, positions):
        signals = []
        holding_codes = list(positions.keys())
        available_codes = [c for c in self.constituents if c in daily_data]

        for code in holding_codes:
            if code in daily_data:
                row = daily_data[code]
                cost = positions[code]["avg_cost"]
                current_price = float(row.get("close", 0))
                if current_price <= 0:
                    continue
                ret = (current_price - cost) / cost

                if ret <= self.stop_loss_pct:
                    signals.append({
                        "stock_code": code, "direction": "SELL",
                        "price": current_price, "volume": positions[code]["volume"],
                        "reason": f"止损 {ret:.2%}"
                    })
                elif ret >= self.take_profit_pct:
                    signals.append({
                        "stock_code": code, "direction": "SELL",
                        "price": current_price, "volume": positions[code]["volume"],
                        "reason": f"止盈 {ret:.2%}"
                    })

        slots = self.max_positions - len(holding_codes)
        if slots <= 0:
            return signals

        candidates = []
        for code in available_codes:
            if code in holding_codes:
                continue
            row = daily_data[code]
            score = self._score_stock(code, row, daily_data)
            if score >= self.entry_score_threshold:
                candidates.append((code, score, row))

        candidates.sort(key=lambda x: x[1], reverse=True)

        for code, score, row in candidates[:slots]:
            close_price = float(row.get("close", 0))
            if close_price <= 0:
                continue
            amount_per_stock = self.collector_capital * self.position_pct
            volume = int(amount_per_stock / close_price / 100) * 100
            if volume < 100:
                continue
            signals.append({
                "stock_code": code, "direction": "BUY",
                "price": close_price, "volume": volume,
                "reason": f"主线评分 {score:.0f}"
            })

        return signals

    def _score_stock(self, code, row, daily_data):
        score = 0
        try:
            change_pct = float(row.get("change_pct", 0))
            if change_pct > 9:
                score += 35
            elif change_pct > 5:
                score += 25
            elif change_pct > 2:
                score += 15
            elif change_pct > 0:
                score += 10
            else:
                score += 5
        except Exception:
            score += 10

        try:
            volume = float(row.get("volume", 0))
            turnover = float(row.get("amount", 0))
            if turnover > 500000000:
                score += 30
            elif turnover > 100000000:
                score += 20
            elif turnover > 50000000:
                score += 10
            else:
                score += 5
        except Exception:
            score += 10

        try:
            if str(code).startswith("6") or str(code).startswith("0"):
                score += 15
            elif str(code).startswith("3") or str(code).startswith("6"):
                score += 10
        except Exception:
            score += 5

        return score

    def set_capital(self, capital):
        self.collector_capital = capital


def run_backtest(concept_code="BK0891", start_date="2024-01-01", end_date="2025-01-01", capital=1000000):
    print("=" * 70)
    print(f"主线量化回测系统 - 本地数据")
    print(f"概念板块: {concept_code}")
    print(f"回测区间: {start_date} ~ {end_date}")
    print(f"初始资金: {capital:,.0f}")
    print("=" * 70)

    # --- Load data from local duckdb ---
    print("\n[1/5] Loading data from local duckdb...")
    db_path = "/workspace/data/meta.duckdb"
    conn = duckdb.connect(db_path)

    # Get concept constituents
    constituents_df = conn.execute("SELECT DISTINCT stock_code FROM concept_constituent WHERE concept_code = ?", [concept_code]).df()
    if constituents_df.empty:
        print("  No constituents found for concept, using all stocks...")
        constituents_df = conn.execute("SELECT DISTINCT stock_code FROM stock_info LIMIT 50").df()
        concept_name = concept_code
    else:
        concept_info = conn.execute("SELECT concept_name FROM concept_info WHERE concept_code = ? LIMIT 1", [concept_code]).df()
        concept_name = concept_info.iloc[0]['concept_name'] if not concept_info.empty else concept_code
    constituents = constituents_df['stock_code'].tolist()
    print(f"  Concept: {concept_name}")
    print(f"  Constituents: {len(constituents)}")

    # Get K-line data
    print("\n[2/5] Loading K-line data...")
    kline_df = conn.execute(f"""
        SELECT * FROM daily_kline
        WHERE trade_date >= ? AND trade_date <= ?
        AND stock_code IN {tuple(constituents)}
        ORDER BY stock_code, trade_date
    """, [start_date, end_date]).df()
    if kline_df.empty:
        print("  No K-line data found! Using mock data...")
        stock_data = _generate_mock_data(constituents[0], start_date, end_date)
        constituents = [constituents[0]]
    else:
        stock_data = {}
        for code in constituents:
            df = kline_df[kline_df['stock_code'] == code].copy()
            df = df.sort_values('trade_date').reset_index(drop=True)
            if not df.empty:
                stock_data[code] = df
        print(f"  Loaded K-line for {len(stock_data)} stocks")

    conn.close()

    print(f"\n[3/5] Initializing strategy and backtest engine...")
    strategy = MainlineBacktestStrategy(None, concept_code, list(stock_data.keys()))
    strategy.set_capital(capital)
    engine = BacktestEngine(initial_capital=capital, commission=0.0003, slippage=0.001)

    print(f"\n[4/5] Running backtest...")

    def data_provider(code, sd, ed):
        return stock_data.get(code)

    result = engine.run(strategy, start_date, end_date, list(stock_data.keys()), data_provider)

    print(f"\n[5/5] Calculating performance metrics...")
    metrics = MetricsCalculator.calculate_all(result.equity_curve, result.trades)

    return result, metrics, stock_data, concept_name


def _generate_mock_data(code, start_date, end_date):
    np.random.seed(hash(str(code)) % 2**31)
    dates = pd.date_range(start=start_date, end=end_date, freq="B")
    n = len(dates)
    if n < 10:
        n = 100
        dates = pd.date_range(start=start_date, periods=n, freq="B")

    base_price = np.random.uniform(10, 500)
    drift = np.random.uniform(-0.0005, 0.0015)
    volatility = np.random.uniform(0.015, 0.05)
    rets = np.random.normal(drift, volatility, n)
    prices = base_price * np.cumprod(1 + rets)
    pre_close = np.concatenate([[base_price], prices[:-1]])

    data = []
    for i, (date, price) in enumerate(zip(dates, prices)):
        open_p = price * (1 + np.random.uniform(-0.03, 0.03))
        high_p = max(open_p, price) * (1 + abs(np.random.uniform(0, 0.03)))
        low_p = min(open_p, price) * (1 - abs(np.random.uniform(0, 0.03)))
        volume = int(abs(np.random.normal(5000000, 2000000)))
        change_pct = rets[i] * 100
        change = price - pre_close[i]
        data.append({
            "trade_date": date.strftime("%Y-%m-%d"),
            "open": round(open_p, 2), "close": round(price, 2),
            "high": round(high_p, 2), "low": round(low_p, 2),
            "volume": volume, "amount": round(volume * price, 2),
            "change_pct": round(change_pct, 2), "change": round(change, 2),
            "turnover_ratio": round(abs(np.random.uniform(1, 15)), 2),
            "pre_close": round(pre_close[i], 2),
            "stock_code": code,
        })
    return pd.DataFrame(data)


