    report.append(f"  平均盈利:     {metrics.get('avg_profit', 0):,.2f} 元")
    report.append(f"  平均亏损:     {metrics.get('avg_loss', 0):,.2f} 元")
    report.append(f"  平均持仓天数: {metrics.get('avg_hold_days', 0):.1f} 天")
